from pydantic import BaseModel, field_validator

class UserCreate(BaseModel):
    username: str
    password: str
    password_confirm: str

    @field_validator("username")
    @classmethod
    def username_must_be_lowercase(cls, v: str) -> str:
        if v != v.lower():
            raise ValueError("Username must be lowercase")
        return v

    @field_validator("password")
    @classmethod
    def password_strong_enough(cls, v: str) -> str:
        if len(v) < 8:
            raise ValueError("Password must be at least 8 characters")
        if not any(c.isdigit() for c in v):
            raise ValueError("Password must contain at least one digit")
        return v

@field_validator("tags", mode="before")
@classmethod
def parse_comma_separated_tags(cls, v):
    if isinstance(v, str):
        return [tag.strip() for tag in v.split(",")]
    return v

from pydantic import BaseModel, model_validator

class DateRange(BaseModel):
    start_date: date
    end_date: date

    @model_validator(mode="after")
    def end_must_be_after_start(self) -> "DateRange":
        if self.end_date <= self.start_date:
            raise ValueError("end_date must be after start_date")
        return self

class PasswordForm(BaseModel):
    password: str
    password_confirm: str

    @model_validator(mode="after")
    def passwords_must_match(self) -> "PasswordForm":
        if self.password != self.password_confirm:
            raise ValueError("Passwords do not match")
        return self

from pydantic import BaseModel, computed_field

class Rectangle(BaseModel):
    width: float
    height: float

    @computed_field
    @property
    def area(self) -> float:
        return self.width * self.height

rect = Rectangle(width=3.0, height=4.0)
print(rect.model_dump())
# {"width": 3.0, "height": 4.0, "area": 12.0}

from pydantic import BaseModel, model_serializer

class Money(BaseModel):
    amount: int  # Store as cents
    currency: str

    @model_serializer
    def serialize_model(self) -> dict:
        return {
            "amount": self.amount / 100,  # Output as dollars
            "currency": self.currency,
            "formatted": f"{self.currency} {self.amount / 100:.2f}"
        }

